#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 12 (Layer 5): sondas de protocolo AXI4.
#
# Verifica el motor DMA maestro ANTES de conectarlo a la NPU, siguiendo el
# mismo patron que las sondas de tiling del Paso 5.
#
# Subconjunto congelado del master: solo rafagas INCR, ARLEN <= 15 (16
# transferencias de 4 B = 64 B, lejos de la frontera de 4 KB), ID fijo en 0,
# RRESP y BRESP comprobados y reportados.
#
# Sondas:
#   1  rafaga simple de 64 B, escribir y releer
#   2  multi-rafaga: 2560 B (el caso real de W3) en 40 rafagas encadenadas
#   3  backpressure: el esclavo baja RVALID cada 3 transferencias
#   4  error: direccion que responde SLVERR, debe propagarse a err_out
#
# Instala tambien el mapa de memoria congelado (npu_axi_pkg.vhd):
#   DDR 0x70000000: W1 +0x0, B1 +0x100, W2 +0x1000, B2 +0x1800,
#                   W3 +0x2000, B3 +0x2C00, imagen +0x10000, resultado +0x20000
#   AXI 0x80000000: CTRL 0x00, STATUS 0x04, ID 0x08, BASE 0x0C, ERRCODE 0x10
#
# Requiere: ghdl 4.1.0 --std=08. Requiere los Pasos 1-11.
# Linea esperada al final:
# NPU PASO12 OK SONDAS AXI 4/4 PASS
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/rtl/npu_top.vhd" ]; then
  echo "FALLO: falta rtl/npu_top.vhd (corre primero los Pasos 1-11)"; exit 1
fi
mkdir -p "$DIR/rtl" "$DIR/tb"
base64 -d << "EOF" > "$DIR/rtl/npu_axi_pkg.vhd"

EOF
base64 -d << "EOF" > "$DIR/rtl/npu_dma.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/axi_ddr_model.vhd"

EOF
base64 -d << "EOF" > "$DIR/tb/tb_axi_sondas.vhd"

EOF
base64 -d << "EOF" > "$DIR/run_axi_sondas.sh"

EOF
chmod +x "$DIR/run_axi_sondas.sh"
cd "$DIR"
bash run_axi_sondas.sh
)
